sql:
SELECT COUNT(DISTINCT a.agent_name)
FROM agents a
JOIN experiments e ON a.agent_id = e.agent_id;

SELECT agents.agent_name, agents.model_type, experiments.experiment_name, experiments.status
FROM agents
INNER JOIN experiments ON agents.agent_id = experiments.agent_id;

external_knowledge:
- 'sowers of knowledge' metaphorically refers to the users who create agents;
- 'planted seeds' symbolically represents the creation of agents by users;
- 'sprouted into experiments bearing golden fruits' metaphorically describes experiments that have high accuracy, precision, and recall metrics;
- 'harvest test' represents experiments named or described with 'test';
- 'validated by at least a dozen witnesses' refers to experiments having more than 10 outcomes.

sql:
SELECT strftime('%Y-%m', created_at) AS Month, COUNT(agent_id) AS Agents_Created
FROM agents
GROUP BY strftime('%Y-%m', created_at);

SELECT experiment_name, description, status
FROM experiments
WHERE experiment_id IN (SELECT experiment_id FROM experiment_versions);

SELECT AVG(ndens_current0) AS average_current
FROM experiment_outcomes
WHERE experiment_id = 1;

SELECT agent_name, model_type, agent_id, creator_id, description
FROM agents
WHERE agent_id = 1 AND creator_id = 1;
